import { useState, useCallback, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import ShpeHatAnimation from './ShpeHatAnimation';

const textVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.2, delayChildren: 0.1 },
  },
};

const lineVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.7, ease: 'easeOut' } },
};

const gradientStyle = {
  letterSpacing: '0.2em',
  fontSize: 'clamp(1.5rem, 4vw, 3rem)',
  fontWeight: 700,
  textTransform: 'uppercase',
  background: 'linear-gradient(135deg, #D33A02, #FD652F, #0070C0, #001F5B, #D33A02, #FD652F)',
  backgroundSize: '300% 300%',
  WebkitBackgroundClip: 'text',
  WebkitTextFillColor: 'transparent',
  backgroundClip: 'text',
  animation: 'gradientShift 4s ease infinite',
};

const sectionAnim = {
  initial: { opacity: 0, y: 40 },
  whileInView: { opacity: 1, y: 0 },
  viewport: { once: true },
  transition: { duration: 0.7 },
};

const valueCards = [
  { label: 'Familia', emoji: '👨‍👩‍👧', color: '#001F5B' },
  { label: 'Service', emoji: '🤝', color: '#0070C0' },
  { label: 'Education', emoji: '📚', color: '#D33A02' },
  { label: 'Resilience', emoji: '💪', color: '#FD652F' },
];

const events = [
  {
    title: 'SHPE Social — FIFA World Cup Watch Party',
    date: 'June 18th · 6:00 PM CT',
    description: 'Join us for the Mexico 🇲🇽 vs South Korea 🇰🇷 match! RSVP for address details and updates 😊',
    border: '#FD652F',
    rsvp: '#',
  },
  {
    title: 'Virtual Event with ARM & SHPE Phoenix',
    date: 'June 18th · 6:00 PM CT',
    description: 'Join SHPE Phoenix Professional and Unidos@ARM alongside Platinum Sponsor ARM — a semiconductor and software design company growing new facilities in Austin! Zoom link sent via RSVP email.',
    border: '#0070C0',
    rsvp: '#',
  },
];

export default function Home() {
  const alreadyPlayed = sessionStorage.getItem('introPlayed');
  const [stage, setStage] = useState(alreadyPlayed ? 'done' : 'video');
  const [fadeOut, setFadeOut] = useState(false);
  const [hatDone, setHatDone] = useState(!!alreadyPlayed);
  const videoRef = useRef(null);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.playbackRate = 1.5;
    }
  }, []);

  const handleVideoEnd = useCallback(() => {
    setFadeOut(true);
    setTimeout(() => {
      setFadeOut(false);
      setStage('hat');
    }, 600);
  }, []);

  const handleHatComplete = useCallback(() => {
    sessionStorage.setItem('introPlayed', 'true');
    setHatDone(true);
  }, []);

  return (
    <main className="font-sans">
      <style>{`
        @keyframes gradientShift {
          0%   { background-position: 0% 50%; }
          50%  { background-position: 100% 50%; }
          100% { background-position: 0% 50%; }
        }
        .intro-video { object-fit: cover; }
        .hat-margin  { margin-top: -80px; }
        @media (max-width: 640px) {
          .intro-video { object-fit: contain; }
          .hat-margin  { margin-top: -20px; }
        }
        .value-card:hover { transform: translateY(-8px); }
        .value-card { transition: transform 0.3s ease; }
        .rsvp-btn:hover { opacity: 0.85; }
      `}</style>

      {/* ── INTRO: VIDEO ── */}
      {stage === 'video' && (
        <div
          style={{
            transition: 'opacity 0.6s ease',
            opacity: fadeOut ? 0 : 1,
            width: '100%',
            height: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            overflow: 'hidden',
          }}
        >
          <video
            ref={videoRef}
            src={require('../assets/shpe_animated_video.mp4')}
            autoPlay
            muted
            playsInline
            onEnded={handleVideoEnd}
            className="intro-video"
            style={{ width: '100%', height: '100%' }}
          />
        </div>
      )}

      {/* ── INTRO: HAT ANIMATION ── */}
      {(stage === 'hat' || stage === 'done') && (
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            minHeight: '100vh',
            gap: 0,
          }}
        >
          <AnimatePresence>
            {hatDone && (
              <motion.div
                variants={textVariants}
                initial="hidden"
                animate="visible"
                style={{ textAlign: 'center' }}
              >
                <motion.p variants={lineVariants} style={gradientStyle}>
                  Bienvenido a
                </motion.p>
              </motion.div>
            )}
          </AnimatePresence>

          <div className="hat-margin">
            <ShpeHatAnimation onComplete={handleHatComplete} speed={stage === 'done' ? 999 : 1.4} />
          </div>
        </div>
      )}

      {/* ══════════════════════════════════════
          SECTION 1 — OUR MISSION
      ══════════════════════════════════════ */}
      <motion.section
        {...sectionAnim}
        style={{
          background: 'linear-gradient(135deg, #001F5B 0%, #0a1a3a 100%)',
          padding: '5rem 1.5rem',
          textAlign: 'center',
        }}
      >
        <p style={{ color: '#FD652F', letterSpacing: '0.2em', fontSize: '0.85rem', fontWeight: 700, textTransform: 'uppercase', marginBottom: '0.75rem' }}>
          Who We Are
        </p>
        <h2 style={{ color: '#fff', fontSize: 'clamp(2rem, 5vw, 3.5rem)', fontWeight: 900, marginBottom: '1.5rem', lineHeight: 1.1 }}>
          Our Mission
        </h2>
        <div style={{ width: '60px', height: '4px', background: 'linear-gradient(90deg, #FD652F, #0070C0)', borderRadius: '2px', margin: '0 auto 2rem' }} />
        <p style={{ color: '#c8d8e8', fontSize: 'clamp(1rem, 2vw, 1.2rem)', maxWidth: '720px', margin: '0 auto 2.5rem', lineHeight: 1.8 }}>
          SHPE changes lives by empowering the Hispanic community to realize its fullest potential and to impact the world through STEM awareness, access, support, and development.
        </p>
        <a
          href="/#/about"
          style={{
            display: 'inline-block',
            background: '#FD652F',
            color: '#fff',
            fontWeight: 700,
            fontSize: '1rem',
            padding: '0.8rem 2.5rem',
            borderRadius: '50px',
            textDecoration: 'none',
            letterSpacing: '0.05em',
            transition: 'opacity 0.2s',
          }}
          onMouseOver={e => e.currentTarget.style.opacity = '0.85'}
          onMouseOut={e => e.currentTarget.style.opacity = '1'}
        >
          Learn More
        </a>
      </motion.section>

      {/* ══════════════════════════════════════
          SECTION 2 — SHPE VALUES
      ══════════════════════════════════════ */}
      <motion.section
        {...sectionAnim}
        style={{ background: '#f8f9fb', padding: '5rem 1.5rem', textAlign: 'center' }}
      >
        <p style={{ color: '#0070C0', letterSpacing: '0.2em', fontSize: '0.85rem', fontWeight: 700, textTransform: 'uppercase', marginBottom: '0.5rem' }}>
          What Drives Us
        </p>
        <h2 style={{ color: '#001F5B', fontSize: 'clamp(2rem, 5vw, 3rem)', fontWeight: 900, marginBottom: '3rem' }}>
          SHPE Values
        </h2>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))', gap: '1.5rem', maxWidth: '900px', margin: '0 auto' }}>
          {valueCards.map(({ label, emoji, color }) => (
            <div
              key={label}
              className="value-card"
              style={{
                background: color,
                borderRadius: '16px',
                padding: '2.5rem 1rem',
                color: '#fff',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '1rem',
                boxShadow: '0 4px 20px rgba(0,0,0,0.12)',
                cursor: 'default',
              }}
            >
              <span style={{ fontSize: '2.5rem' }}>{emoji}</span>
              <span style={{ fontWeight: 800, fontSize: '1.2rem', letterSpacing: '0.03em' }}>{label}</span>
            </div>
          ))}
        </div>
      </motion.section>

      {/* ══════════════════════════════════════
          SECTION 3 — UPCOMING EVENTS
      ══════════════════════════════════════ */}
      <motion.section
        {...sectionAnim}
        style={{ background: '#eef2f7', padding: '5rem 1.5rem', textAlign: 'center' }}
      >
        <p style={{ color: '#D33A02', letterSpacing: '0.2em', fontSize: '0.85rem', fontWeight: 700, textTransform: 'uppercase', marginBottom: '0.5rem' }}>
          What's Coming Up
        </p>
        <h2 style={{ color: '#001F5B', fontSize: 'clamp(2rem, 5vw, 3rem)', fontWeight: 900, marginBottom: '3rem' }}>
          Upcoming Events
        </h2>
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '1.5rem', maxWidth: '960px', margin: '0 auto 2rem', justifyContent: 'center' }}>
          {events.map((ev) => (
            <div
              key={ev.title}
              style={{
                background: '#fff',
                borderLeft: `5px solid ${ev.border}`,
                borderRadius: '12px',
                padding: '2rem',
                flex: '1 1 300px',
                maxWidth: '440px',
                textAlign: 'left',
                boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
              }}
            >
              <p style={{ color: ev.border, fontWeight: 700, fontSize: '0.8rem', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '0.4rem' }}>
                {ev.date}
              </p>
              <h3 style={{ color: '#001F5B', fontWeight: 800, fontSize: '1.1rem', marginBottom: '0.75rem', lineHeight: 1.3 }}>
                {ev.title}
              </h3>
              <p style={{ color: '#555', fontSize: '0.95rem', lineHeight: 1.7, marginBottom: '1.5rem' }}>
                {ev.description}
              </p>
              <a
                href={ev.rsvp}
                className="rsvp-btn"
                style={{
                  display: 'inline-block',
                  background: ev.border,
                  color: '#fff',
                  fontWeight: 700,
                  fontSize: '0.9rem',
                  padding: '0.6rem 1.8rem',
                  borderRadius: '50px',
                  textDecoration: 'none',
                  transition: 'opacity 0.2s',
                }}
              >
                RSVP Here
              </a>
            </div>
          ))}
        </div>
        <a
          href="https://calendar.google.com"
          target="_blank"
          rel="noopener noreferrer"
          style={{
            display: 'inline-block',
            border: '2px solid #0070C0',
            color: '#0070C0',
            fontWeight: 700,
            fontSize: '0.9rem',
            padding: '0.6rem 1.8rem',
            borderRadius: '50px',
            textDecoration: 'none',
            transition: 'all 0.2s',
          }}
          onMouseOver={e => { e.currentTarget.style.background = '#0070C0'; e.currentTarget.style.color = '#fff'; }}
          onMouseOut={e => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = '#0070C0'; }}
        >
          📅 Add SHPE Austin Events to Google Calendar
        </a>
      </motion.section>

      {/* ══════════════════════════════════════
          SECTION 4 — MEMBERSHIP
      ══════════════════════════════════════ */}
      <motion.section
        {...sectionAnim}
        style={{ background: '#fff', padding: '5rem 1.5rem' }}
      >
        <div style={{ maxWidth: '900px', margin: '0 auto', display: 'flex', flexWrap: 'wrap', gap: '3rem', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ flex: '1 1 300px' }}>
            <p style={{ color: '#FD652F', letterSpacing: '0.2em', fontSize: '0.85rem', fontWeight: 700, textTransform: 'uppercase', marginBottom: '0.5rem' }}>
              Join the Family
            </p>
            <h2 style={{ color: '#001F5B', fontSize: 'clamp(2rem, 4vw, 2.8rem)', fontWeight: 900, marginBottom: '1rem', lineHeight: 1.2 }}>
              Membership
            </h2>
            <p style={{ color: '#555', fontSize: '1.05rem', lineHeight: 1.8 }}>
              Are you a recent grad or just moved to Austin? Become a member and learn more about what SHPE Austin has to offer!
            </p>
          </div>
          <div
            style={{
              flex: '1 1 260px',
              background: '#001F5B',
              borderRadius: '20px',
              padding: '2.5rem',
              textAlign: 'center',
              boxShadow: '0 8px 30px rgba(0,31,91,0.2)',
            }}
          >
            <span style={{ fontSize: '3rem' }}>🎓</span>
            <p style={{ color: '#c8d8e8', fontSize: '1rem', marginTop: '1rem', marginBottom: '1.5rem', lineHeight: 1.7 }}>
              Unlock networking, events, scholarships, and professional development opportunities.
            </p>
            <a
              href="/#/membership"
              style={{
                display: 'inline-block',
                background: '#FD652F',
                color: '#fff',
                fontWeight: 700,
                fontSize: '1rem',
                padding: '0.75rem 2rem',
                borderRadius: '50px',
                textDecoration: 'none',
                transition: 'opacity 0.2s',
              }}
              onMouseOver={e => e.currentTarget.style.opacity = '0.85'}
              onMouseOut={e => e.currentTarget.style.opacity = '1'}
            >
              Click here for more information
            </a>
          </div>
        </div>
      </motion.section>

      {/* ══════════════════════════════════════
          SECTION 5 — BECOME A SPONSOR
      ══════════════════════════════════════ */}
      <motion.section
        {...sectionAnim}
        style={{ background: '#001F5B', padding: '5rem 1.5rem', textAlign: 'center' }}
      >
        <p style={{ color: '#72A9BE', letterSpacing: '0.2em', fontSize: '0.85rem', fontWeight: 700, textTransform: 'uppercase', marginBottom: '0.5rem' }}>
          Partner With Us
        </p>
        <h2 style={{ color: '#fff', fontSize: 'clamp(2rem, 5vw, 3rem)', fontWeight: 900, marginBottom: '1.5rem' }}>
          Become a Sponsor!
        </h2>
        <div style={{ width: '60px', height: '4px', background: 'linear-gradient(90deg, #FD652F, #0070C0)', borderRadius: '2px', margin: '0 auto 2rem' }} />
        <p style={{ color: '#c8d8e8', fontSize: 'clamp(1rem, 2vw, 1.15rem)', maxWidth: '680px', margin: '0 auto 1rem', lineHeight: 1.8 }}>
          SHPE Austin is always looking for new companies to help in the professional development and advancement of engineers in the City of Austin.
        </p>
        <p style={{ color: '#c8d8e8', fontSize: '1rem', marginBottom: '2.5rem' }}>
          Interested in supporting our team? Contact us for a Corporate Solicitation Packet.
        </p>
        <a
          href="mailto:contact@shpeaustin.com"
          style={{
            display: 'inline-block',
            background: '#FD652F',
            color: '#fff',
            fontWeight: 700,
            fontSize: '1rem',
            padding: '0.8rem 2.5rem',
            borderRadius: '50px',
            textDecoration: 'none',
            transition: 'opacity 0.2s',
          }}
          onMouseOver={e => e.currentTarget.style.opacity = '0.85'}
          onMouseOut={e => e.currentTarget.style.opacity = '1'}
        >
          contact@shpeaustin.com
        </a>
      </motion.section>

      {/* ══════════════════════════════════════
          SECTION 6 — DONATE
      ══════════════════════════════════════ */}
      <motion.section
        {...sectionAnim}
        style={{
          background: 'linear-gradient(135deg, #FD652F 0%, #D33A02 100%)',
          padding: '5rem 1.5rem',
          textAlign: 'center',
        }}
      >
        <p style={{ color: 'rgba(255,255,255,0.75)', letterSpacing: '0.2em', fontSize: '0.85rem', fontWeight: 700, textTransform: 'uppercase', marginBottom: '0.5rem' }}>
          Make an Impact
        </p>
        <h2 style={{ color: '#fff', fontSize: 'clamp(2rem, 5vw, 3.5rem)', fontWeight: 900, marginBottom: '1.5rem' }}>
          Donate!
        </h2>
        <p style={{ color: 'rgba(255,255,255,0.9)', fontSize: 'clamp(1rem, 2vw, 1.15rem)', maxWidth: '640px', margin: '0 auto 2.5rem', lineHeight: 1.8 }}>
          Your generosity helps us achieve our goals of giving back to the community — from scholarships to students, to donations to food banks, and so much more.
        </p>
        <a
          href="#donate"
          style={{
            display: 'inline-block',
            background: '#fff',
            color: '#D33A02',
            fontWeight: 800,
            fontSize: '1.1rem',
            padding: '0.9rem 3rem',
            borderRadius: '50px',
            textDecoration: 'none',
            boxShadow: '0 4px 20px rgba(0,0,0,0.15)',
            transition: 'transform 0.2s, box-shadow 0.2s',
          }}
          onMouseOver={e => { e.currentTarget.style.transform = 'translateY(-3px)'; e.currentTarget.style.boxShadow = '0 8px 30px rgba(0,0,0,0.2)'; }}
          onMouseOut={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = '0 4px 20px rgba(0,0,0,0.15)'; }}
        >
          Donate Now
        </a>
        <p style={{ color: 'rgba(255,255,255,0.8)', fontSize: '0.95rem', marginTop: '1.5rem', fontStyle: 'italic' }}>
          Thank you for your support! 🙏
        </p>
      </motion.section>
    </main>
  );
}
